ALTER TABLE `waste_management_ecm`.`maintenance`.`pm_schedule` ADD CONSTRAINT `fk_maintenance_pm_schedule_type_id` FOREIGN KEY (`type_id`) REFERENCES `waste_management_ecm`.`maintenance`.`type`(`type_id`);
